    'upcoming-follow-up': 'bg-blue-100 text-blue-600',
    'new-lead': 'bg-green-100 text-green-600',
    'lead-won': 'bg-emerald-100 text-emerald-600',
    'lead-lost': 'bg-slate-100 text-slate-600',
